AND sender_type = 'admin'
AND lida = false
);
END;
$$;


--
-- Name: create_contract_from_lead(uuid, uuid, uuid, jsonb, jsonb, jsonb, text, text, timestamp with time zone, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_contract_from_lead(p_template_id uuid, p_lead_id uuid, p_user_id uuid, p_lead_data_json jsonb, p_user_data_json jsonb, p_payment_details_json jsonb, p_user_signature_base64 text, p_observacoes_user text, p_expires_at timestamp with time zone, p_content_override text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_token UUID;
  v_final_lead_data JSONB;
  v_contract contracts;
BEGIN
  -- Gerar token
  v_token := gen_random_uuid();

  -- Mesclar content_override no lead_data_json se fornecido
  v_final_lead_data := COALESCE(p_lead_data_json, '{}'::jsonb);
  
  IF p_content_override IS NOT NULL THEN
    v_final_lead_data := jsonb_set(v_final_lead_data, '{content_override}', to_jsonb(p_content_override));
  END IF;

  -- Inserir contrato
  INSERT INTO contracts (
    template_id,
    lead_id,
    user_id,
    token,
    lead_data_json,
    user_data_json,
    payment_details_json,
    user_signature_base64,
    observacoes_user,
    expires_at,
    status
  ) VALUES (
    p_template_id,
    p_lead_id,
    p_user_id,
    v_token,
    v_final_lead_data,
    p_user_data_json,
    p_payment_details_json,
    p_user_signature_base64,
    p_observacoes_user,
    p_expires_at,
    'pending'
  )
  RETURNING * INTO v_contract;

  -- Retorna JSON para evitar erro de serialização do PostgREST
  RETURN to_json(v_contract);
END;
$$;


--
-- Name: create_notification(uuid, text, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_notification(user_id_param uuid, title_param text, message_param text, type_param text DEFAULT 'info'::text, data_param jsonb DEFAULT NULL::jsonb) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  notification_id uuid;
BEGIN
  INSERT INTO notifications (user_id, title, message, type, data)
  VALUES (user_id_param, title_param, message_param, type_param, data_param)
  RETURNING id INTO notification_id;

  RETURN notification_id;
END;
$$;


