--
-- Name: gerar_token_avaliacao(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.gerar_token_avaliacao(lead_id_param uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
token_gerado text;
BEGIN
token_gerado := encode(gen_random_bytes(32), 'base64');
token_gerado := replace(token_gerado, '/', '_');
token_gerado := replace(token_gerado, '+', '-');

UPDATE leads
SET token_avaliacao = token_gerado,
pode_avaliar = true,
avaliacao_solicitada_em = now()
WHERE id = lead_id_param;

RETURN token_gerado;
END;
$$;


