  SELECT db.data_bloqueada
  FROM public.datas_bloqueadas AS db
  WHERE db.user_id = p_user_id;
END;
$$;


--
-- Name: get_public_contract_data(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_public_contract_data(p_token uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    contract_data RECORD;
    template_data RECORD;
    business_data RECORD;
    result JSONB;
BEGIN
    -- Busca o contrato pelo token
    SELECT * INTO contract_data FROM public.contracts WHERE token = p_token;

    IF NOT FOUND THEN
        RETURN NULL;
    END IF;

    -- Busca o template associado
    SELECT id, name, content_text INTO template_data FROM public.contract_templates WHERE id = contract_data.template_id;

    -- Busca os dados da empresa associada
    SELECT business_name, cnpj, address, city, state, zip_code, phone, email, pix_key, bank_name, bank_agency, bank_account, bank_account_type
    INTO business_data
    FROM public.user_business_settings
    WHERE user_id = contract_data.user_id;

    -- Monta o objeto de retorno
    result := jsonb_build_object(
        'contract', to_jsonb(contract_data),
        'template', to_jsonb(template_data),
        'business_settings', to_jsonb(business_data)
    );

    RETURN result;
END;
$$;


--
-- Name: handle_contract_signed(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.handle_contract_signed() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_lead_nome text;
  v_tipo_evento text;
  v_cidade text;
  v_data_evento date;
BEGIN
  IF NEW.status = 'signed' AND (OLD.status IS NULL OR OLD.status != 'signed') THEN
    v_data_evento := COALESCE(
      (NEW.client_data_json->>'data_evento')::date,
      (NEW.lead_data_json->>'data_evento')::date
    );

    IF v_data_evento IS NOT NULL THEN
      IF NOT EXISTS (
        SELECT 1 FROM public.eventos_agenda 
        WHERE lead_id = NEW.lead_id AND data_evento = v_data_evento
      ) THEN
        v_lead_nome := COALESCE(NEW.lead_data_json->>'nome_cliente', NEW.client_data_json->>'nome_completo', 'Cliente');
        v_tipo_evento := COALESCE(NEW.lead_data_json->>'tipo_evento', 'Evento');
        v_cidade := COALESCE(NEW.client_data_json->>'cidade_evento', NEW.lead_data_json->>'cidade_evento', '');

        INSERT INTO public.eventos_agenda (
          user_id, lead_id, data_evento, tipo_evento, cliente_nome, cidade, status, origem, observacoes
        ) VALUES (
          NEW.user_id, NEW.lead_id, v_data_evento, v_tipo_evento, v_lead_nome, v_cidade, 'confirmado', 'lead_convertido', 'Gerado via assinatura do contrato pelo cliente'
        );
      END IF;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: handle_contract_signed_notification(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.handle_contract_signed_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    client_name text;
BEGIN
    -- Dispara apenas quando o status muda para 'signed'
    IF OLD.status <> 'signed' AND NEW.status = 'signed' THEN
        -- Tenta extrair o nome do cliente do JSON salvo no contrato
        client_name := NEW.lead_data_json->>'nome_cliente';
        
        INSERT INTO public.notifications (user_id, type, message, link, related_id)
        VALUES (
            NEW.user_id,
            'contract_signed',
            'Contrato assinado por: ' || COALESCE(client_name, 'Cliente'),
            '/dashboard?page=contratos',
            NEW.id
        );
    END IF;
    RETURN NEW;
END;
$$;


