-- Name: handle_payment_failed(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.handle_payment_failed() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare
  edge_function_url text := 'https://qrqcnrmaatthvyngwfkb.supabase.co/functions/v1/send-notification';
  anon_key text := 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFycWNucm1hYXR0aHZ5bmd3ZmtiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjczNDc1NzgsImV4cCI6MjA4MjkyMzU3OH0.gK2gAHvY17Q5KKiy-cC5JuDpEG5U5HrunfEpzeWpSbo';
  payload jsonb;
begin
  -- Dispara quando o status muda para 'past_due' ou 'unpaid'
  if (new.status in ('past_due', 'unpaid')) 
     and (old.status is distinct from new.status) then
    
    payload := jsonb_build_object(
      'user_id', new.user_id,
      'title', 'Falha no Pagamento 💳',
      'message', 'Não conseguimos processar o pagamento da sua assinatura. Atualize seu cartão para evitar interrupções.',
      'type', 'payment_failed',
      'data', jsonb_build_object('subscription_id', new.id)
    );

    perform
      net.http_post(
        url := edge_function_url,
        headers := jsonb_build_object(
          'Content-Type', 'application/json',
          'Authorization', 'Bearer ' || anon_key
        ),
        body := payload
      );
  end if;
  return new;
end;
$$;


