--
-- Name: insert_public_transactions(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.insert_public_transactions(p_token uuid, p_transactions jsonb) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_contract_id uuid;
  v_lead_id uuid;
BEGIN
  -- 1) Verifica se o token informado realmente pertence a um contrato que foi assinado e obtém o lead_id
  SELECT id, lead_id INTO v_contract_id, v_lead_id
  FROM public.contracts
  WHERE token = p_token AND status = 'signed';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Contrato não encontrado ou não está com status assinado.';
  END IF;

  -- 2) Atualiza o status do Lead relacionado ao contrato para 'convertido'
  IF v_lead_id IS NOT NULL THEN
    UPDATE public.leads
    SET status = 'convertido'
    WHERE id = v_lead_id;
  END IF;

  -- 3) Insere as transações financeiras geradas na revisão do contrato
  IF p_transactions IS NOT NULL AND jsonb_array_length(p_transactions) > 0 THEN
    INSERT INTO public.company_transactions (
      user_id, tipo, origem, descricao, valor, data, status, forma_pagamento, contract_id, is_installment, installment_number, total_installments
    )
    SELECT
      (x->>'user_id')::uuid,
      x->>'tipo',
      x->>'origem',
      x->>'descricao',
      (x->>'valor')::numeric,
      (x->>'data')::date,
      x->>'status',
      x->>'forma_pagamento',
      (x->>'contract_id')::uuid,
      (x->>'is_installment')::boolean,
      (x->>'installment_number')::integer,
      (x->>'total_installments')::integer
    FROM jsonb_array_elements(p_transactions) x;
  END IF;
  
END;
$$;


--
-- Name: FUNCTION insert_public_transactions(p_token uuid, p_transactions jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.insert_public_transactions(p_token uuid, p_transactions jsonb) IS 'Converte o lead e insere transações financeiras com base num contrato assinado de forma pública e segura.';


