--
-- Name: limpar_todos_eventos(uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.limpar_todos_eventos(p_user_id uuid, p_incluir_manuais boolean DEFAULT false) RETURNS TABLE(eventos_deletados integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
v_count integer;
BEGIN
IF p_incluir_manuais THEN
DELETE FROM eventos_agenda
WHERE user_id = p_user_id
AND status NOT IN ('concluido', 'cancelado');
ELSE
DELETE FROM eventos_agenda
WHERE user_id = p_user_id
AND importacao_id IS NOT NULL
AND status NOT IN ('concluido', 'cancelado');
END IF;

GET DIAGNOSTICS v_count = ROW_COUNT;
RETURN QUERY SELECT v_count;
END;
$$;


