--
-- Name: notify_expiring_contracts(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_expiring_contracts() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare
  contract record;
  -- URL da Edge Function
  edge_function_url text := 'https://qrqcnrmaatthvyngwfkb.supabase.co/functions/v1/send-notification';
  -- Anon Key (do seu .env)
  anon_key text := 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFycWNucm1hYXR0aHZ5bmd3ZmtiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjczNDc1NzgsImV4cCI6MjA4MjkyMzU3OH0.gK2gAHvY17Q5KKiy-cC5JuDpEG5U5HrunfEpzeWpSbo';
  payload jsonb;
begin
  -- Loop pelos contratos que expiram exatamente daqui a 7 dias
  -- IMPORTANTE: Verifique se o nome da coluna de data é 'data_expiracao' ou 'expiration_date' na sua tabela
  for contract in
    select *
    from public.contracts
    where status = 'signed' -- Apenas contratos ativos
    and data_expiracao::date = (current_date + interval '7 days')::date
  loop
    
    payload := jsonb_build_object(
      'user_id', contract.user_id,
      'title', 'Contrato Expirando ⏳',
      'message', 'O contrato "' || coalesce(contract.title, 'Sem título') || '" expira em 7 dias.',
      'type', 'contract_expiring',
      'data', jsonb_build_object('contract_id', contract.id)
    );

    -- Envia notificação via Edge Function
    perform
      net.http_post(
        url := edge_function_url,
        headers := jsonb_build_object(
          'Content-Type', 'application/json',
          'Authorization', 'Bearer ' || anon_key
        ),
        body := payload
      );
      
  end loop;
end;
$$;


--
-- Name: notify_lead_events(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_lead_events() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
declare
  lead record;
  edge_function_url text := 'https://qrqcnrmaatthvyngwfkb.supabase.co/functions/v1/send-notification';
  anon_key text := 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFycWNucm1hYXR0aHZ5bmd3ZmtiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjczNDc1NzgsImV4cCI6MjA4MjkyMzU3OH0.gK2gAHvY17Q5KKiy-cC5JuDpEG5U5HrunfEpzeWpSbo';
  payload jsonb;
begin
  -- Busca leads convertidos com data de evento para AMANHÃ
  for lead in
    select *
    from public.leads
    where status = 'convertido'
    and data_evento::date = (current_date + interval '1 day')::date
  loop
    
    payload := jsonb_build_object(
      'user_id', lead.user_id,
      'title', 'Evento Amanhã! 📸',
      'message', 'Prepare-se para o evento de ' || coalesce(lead.nome_cliente, 'Cliente') || '.',
      'type', 'event_reminder',
      'data', jsonb_build_object('lead_id', lead.id)
    );

    perform
      net.http_post(
        url := edge_function_url,
        headers := jsonb_build_object('Content-Type', 'application/json', 'Authorization', 'Bearer ' || anon_key),
        body := payload
      );
  end loop;
end;
$$;


--
-- Name: notify_pending_transactions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_pending_transactions() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
declare
  transaction record;
  edge_function_url text := 'https://qrqcnrmaatthvyngwfkb.supabase.co/functions/v1/send-notification';
  anon_key text := 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFycWNucm1hYXR0aHZ5bmd3ZmtiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjczNDc1NzgsImV4cCI6MjA4MjkyMzU3OH0.gK2gAHvY17Q5KKiy-cC5JuDpEG5U5HrunfEpzeWpSbo';
  payload jsonb;
  tipo_texto text;
begin
  -- Busca transações pendentes agendadas para HOJE
  for transaction in
    select *
    from public.company_transactions
    where status = 'pendente'
    and data = current_date
  loop
    
    if transaction.tipo = 'receita' then
      tipo_texto := 'a receber';
    else
      tipo_texto := 'a pagar';
    end if;

    payload := jsonb_build_object(
      'user_id', transaction.user_id,
      'title', 'Financeiro: Vence Hoje 💰',
      'message', 'Lembrete: Você tem uma conta ' || tipo_texto || ' de R$ ' || transaction.valor || ' (' || transaction.descricao || ').',
      'type', 'cash_management_reminder',
      'data', jsonb_build_object('transaction_id', transaction.id)
    );

    perform
      net.http_post(
        url := edge_function_url,
        headers := jsonb_build_object('Content-Type', 'application/json', 'Authorization', 'Bearer ' || anon_key),
        body := payload
      );
  end loop;
end;
$_$;


