--
-- Name: contracts; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.contracts (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    template_id uuid,
    lead_id uuid,
    user_id uuid NOT NULL,
    token uuid DEFAULT gen_random_uuid() NOT NULL,
    lead_data_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    client_data_json jsonb DEFAULT '{}'::jsonb NOT NULL,
    status text DEFAULT 'pending'::text NOT NULL,
    signature_base64 text,
    pdf_url text,
    expires_at timestamp with time zone NOT NULL,
    signed_at timestamp with time zone,
    client_ip text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    user_signature_base64 text,
    user_data_json jsonb DEFAULT '{}'::jsonb,
    content_override text,
    payment_details_json jsonb,
    observacoes_user text,
    observacoes_cliente text,
    CONSTRAINT contracts_status_check CHECK ((status = ANY (ARRAY['pending'::text, 'signed'::text, 'expired'::text, 'cancelled'::text])))
);


--
-- Name: sign_contract(uuid, jsonb, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sign_contract(p_token uuid, p_client_data_json jsonb, p_signature_base64 text, p_client_ip text) RETURNS SETOF public.contracts
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- This SECURITY DEFINER function runs with the privileges of the owner, bypassing RLS.
  -- We include status and expiration checks in the WHERE clause to ensure atomicity and security.

  RETURN QUERY
  UPDATE public.contracts
  SET
    status = 'signed',
    signed_at = now(),
    client_data_json = p_client_data_json,
    signature_base64 = p_signature_base64,
    client_ip = p_client_ip
  WHERE
    token = p_token AND
    status = 'pending' AND -- Only update if it's currently pending
    expires_at >= now()    -- Only update if the link has not expired
  RETURNING *;
END;
$$;


--
-- Name: FUNCTION sign_contract(p_token uuid, p_client_data_json jsonb, p_signature_base64 text, p_client_ip text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.sign_contract(p_token uuid, p_client_data_json jsonb, p_signature_base64 text, p_client_ip text) IS 'Securely signs a contract by its token, updating its status and saving client data. To be called via RPC by anonymous users.';


