--

CREATE FUNCTION public.trg_avaliacoes_after_insert() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- Verifica se existe a coluna profile_id ou user_id na sua tabela de avaliações
  -- Assumindo profile_id conforme seu código anterior
  PERFORM public.fn_insert_notification(
    NEW.profile_id, 
    'new_review', 
    'Nova avaliação recebida de ' || COALESCE(NEW.nome_cliente, 'Cliente'), 
    '/dashboard?page=avaliacoes', 
    NEW.id
  );
  RETURN NEW;
END;
$$;


--
-- Name: trg_contracts_after_update(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_contracts_after_update() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_nome_cliente text;
BEGIN
  -- Dispara apenas quando muda para 'signed'
  IF OLD.status IS DISTINCT FROM NEW.status AND NEW.status = 'signed' THEN
    v_nome_cliente := COALESCE(NEW.lead_data_json->>'nome_cliente', 'Cliente');
    
    PERFORM public.fn_insert_notification(
      NEW.user_id, 
      'contract_signed', 
      'Contrato assinado por: ' || v_nome_cliente, 
      '/dashboard?page=contratos', 
      NEW.id
    );
  END IF;
  RETURN NEW;
END;
$$;


