--
-- Name: agenda_rules; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.agenda_rules (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    user_id uuid NOT NULL,
    name text NOT NULL,
    is_active boolean DEFAULT true NOT NULL,
    rule_type text NOT NULL,
    specific_date date,
    weekday smallint,
    day_of_month_pattern text,
    is_working boolean DEFAULT false NOT NULL,
    fee_percent numeric(5,2) DEFAULT 0.00,
    fee_fixed numeric(10,2) DEFAULT 0.00,
    priority integer DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT agenda_rules_day_of_month_pattern_check CHECK ((day_of_month_pattern = ANY (ARRAY['even'::text, 'odd'::text]))),
    CONSTRAINT agenda_rules_rule_type_check CHECK ((rule_type = ANY (ARRAY['date'::text, 'weekday'::text, 'day_of_month_pattern'::text]))),
    CONSTRAINT agenda_rules_weekday_check CHECK (((weekday >= 0) AND (weekday <= 6))),
    CONSTRAINT chk_rule_params CHECK ((((rule_type = 'date'::text) AND (specific_date IS NOT NULL) AND (weekday IS NULL) AND (day_of_month_pattern IS NULL)) OR ((rule_type = 'weekday'::text) AND (weekday IS NOT NULL) AND (specific_date IS NULL) AND (day_of_month_pattern IS NULL)) OR ((rule_type = 'day_of_month_pattern'::text) AND (day_of_month_pattern IS NOT NULL) AND (specific_date IS NULL) AND (weekday IS NULL))))
);


--
-- Name: COLUMN agenda_rules.rule_type; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.agenda_rules.rule_type IS 'Tipo de regra: ''date'' (data específica), ''weekday'' (dia da semana), ''day_of_month_pattern'' (dia par/ímpar).';


--
-- Name: COLUMN agenda_rules.weekday; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.agenda_rules.weekday IS 'Dia da semana (0=Domingo, 1=Segunda, ..., 6=Sábado).';


--
-- Name: COLUMN agenda_rules.is_working; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.agenda_rules.is_working IS 'Se true, a data é um dia de trabalho (pode ter taxa). Se false, a data é bloqueada.';


--
-- Name: COLUMN agenda_rules.priority; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.agenda_rules.priority IS 'Prioridade da regra. Regras de data específica (ex: 100) têm prioridade sobre regras de dia da semana (ex: 10).';


