    CONSTRAINT eventos_agenda_origem_check CHECK ((origem = ANY (ARRAY['manual'::text, 'csv_import'::text, 'lead_confirmado'::text, 'lead_convertido'::text, 'ics_sync'::text, 'google-calendar-sync'::text]))),
    CONSTRAINT eventos_agenda_status_check CHECK ((status = ANY (ARRAY['confirmado'::text, 'pendente'::text, 'concluido'::text, 'cancelado'::text])))
);


