-- Name: leads; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.leads (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    user_id uuid,
    template_id uuid,
    status text DEFAULT 'novo'::text,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    campos_preenchidos jsonb DEFAULT '{}'::jsonb,
    utm_source text,
    utm_medium text,
    utm_campaign text,
    nome_cliente text,
    email_cliente text,
    telefone_cliente text,
    tipo_evento text,
    data_evento date,
    cidade_evento text,
    valor_total numeric(10,2) DEFAULT 0,
    orcamento_detalhe jsonb,
    url_origem text,
    origem text DEFAULT 'web'::text,
    data_orcamento timestamp with time zone DEFAULT now(),
    data_ultimo_contato timestamp with time zone,
    observacoes text,
    ip_address inet,
    user_agent text,
    session_id text,
    tempo_preenchimento_segundos integer,
    lgpd_consent_timestamp timestamp with time zone,
    lgpd_consent_ip inet,
    lgpd_consent_text text,
    pode_avaliar boolean DEFAULT false,
    avaliacao_solicitada_em timestamp with time zone,
    avaliacao_id uuid,
    token_avaliacao text,
    deleted_at timestamp with time zone,
    dados_formulario jsonb,
    workflow jsonb DEFAULT '[]'::jsonb
);


--
-- Name: COLUMN leads.status; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.status IS 'Status do lead: novo, abandonado, contatado, convertido, perdido, em_negociacao, fazer_followup, finalizado';


--
-- Name: COLUMN leads.tipo_evento; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.tipo_evento IS 'Tipo de evento (ex: casamento,formatura)';


--
-- Name: COLUMN leads.data_evento; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.data_evento IS 'Data do evento selecionado pelo cliente';


--
-- Name: COLUMN leads.cidade_evento; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.cidade_evento IS 'Cidade do evento selecionado pelo cliente';


--
-- Name: COLUMN leads.url_origem; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.url_origem IS 'URL de origem do lead';


--
-- Name: COLUMN leads.lgpd_consent_timestamp; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.lgpd_consent_timestamp IS 'Data e hora em que o cliente consentiu com a LGPD';


--
-- Name: COLUMN leads.lgpd_consent_ip; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.lgpd_consent_ip IS 'Endereço IP do cliente no momento do consentimento (auditoria)';


--
-- Name: COLUMN leads.lgpd_consent_text; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.lgpd_consent_text IS 'Texto exato do termo de consentimento aceito pelo cliente';


--
-- Name: COLUMN leads.dados_formulario; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.dados_formulario IS 'Dados completos do formulário em JSON';


--
-- Name: COLUMN leads.workflow; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.leads.workflow IS 'Array de etapas do workflow: [{id, label, description, deadline, status}]';


--
-- Name: notifications; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.notifications (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    type text NOT NULL,
    message text NOT NULL,
    link text,
    is_read boolean DEFAULT false NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    related_id uuid,
    title text DEFAULT 'Novo lead recebido'::text,
    data jsonb,
    updated_at timestamp with time zone DEFAULT now(),
    read boolean DEFAULT false,
    CONSTRAINT notifications_type_check CHECK ((type = ANY (ARRAY['info'::text, 'warning'::text, 'success'::text, 'error'::text, 'trial'::text, 'lead'::text, 'new_lead'::text, 'lead_abandoned'::text, 'lead_converted'::text, 'contract'::text, 'contract_generated'::text, 'contract_signed'::text, 'review'::text, 'new_review'::text, 'finance'::text, 'payment_failed'::text, 'cash_management_reminder'::text, 'event'::text, 'event_reminder'::text, 'trial_warning'::text])))
);


--
-- Name: paises; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.paises (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    nome character varying(100) NOT NULL,
    codigo character varying(3) NOT NULL,
    user_id uuid,
    created_at timestamp with time zone DEFAULT now(),
    ativo boolean DEFAULT true NOT NULL
);


--
-- Name: COLUMN paises.ativo; Type: COMMENT; Schema: public; Owner: -
