    metadata jsonb
);


--
-- Name: produtos; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.produtos (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    template_id uuid,
    nome text,
    resumo text,
    valor numeric,
    imagem_url text,
    created_at timestamp without time zone DEFAULT now(),
    user_id uuid,
    updated_at timestamp with time zone DEFAULT now(),
    ordem integer DEFAULT 0,
    mostrar_imagem boolean DEFAULT true,
    obrigatorio boolean DEFAULT false,
    unidade text,
    imagem text,
    imagens text[] DEFAULT ARRAY[]::text[],
    carrossel_automatico boolean DEFAULT false,
    permite_multiplas_unidades boolean DEFAULT true,
    desconto_percentual numeric(5,2) DEFAULT 0,
    CONSTRAINT produtos_desconto_percentual_check CHECK (((desconto_percentual >= (0)::numeric) AND (desconto_percentual <= (100)::numeric)))
);


--
-- Name: produtos_servicos; Type: TABLE; Schema: public; Owner: -
--

