-- Name: template_audit; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.template_audit (
    id uuid DEFAULT extensions.uuid_generate_v4() NOT NULL,
    user_id uuid,
    template_id uuid,
    acao text,
    detalhes jsonb,
    registrado_em timestamp without time zone DEFAULT now()
);


--
-- Name: templates; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.templates (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    user_id uuid NOT NULL,
    titulo_template text,
    configuracao_completa jsonb,
    created_at timestamp with time zone DEFAULT now(),
    custom_fields jsonb DEFAULT '[]'::jsonb NOT NULL,
    nome_template text,
    is_published boolean DEFAULT false,
    access_count integer DEFAULT 0,
    last_modified timestamp with time zone DEFAULT now(),
    public_url text,
    nome text,
    criado_em timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    public_config jsonb,
    whatsapp_notification_msg text,
    ocultar_valores_intermediarios boolean DEFAULT false,
    texto_whatsapp text,
    uuid text DEFAULT (gen_random_uuid())::text,
    bloquear_campos_obrigatorios boolean DEFAULT false,
    sistema_sazonal_ativo boolean DEFAULT true,
    modal_info_deslocamento text,
    whatsapp text,
    sistema_geografico_ativo boolean DEFAULT false,
    tema text DEFAULT 'moderno'::text,
    slug_template character varying(100),
    exibir_no_perfil boolean DEFAULT true,
    ordem_exibicao integer DEFAULT 0,
    layout_produtos text DEFAULT 'lista'::text NOT NULL,
    tamanho_imagem_grid text DEFAULT 'medio'::text NOT NULL,
    imagem_apresentacao_url text,
    imagem_despedida_url text,
    layout_produtos_desktop text DEFAULT 'linha'::text,
    whatsapp_followup_mostra_valores_individuais boolean DEFAULT false,
    texto_botao_envio text DEFAULT 'Negociar no WhatsApp'::text,
    forma_pagamento_obrigatoria boolean DEFAULT false NOT NULL,
    ignorar_agenda_global boolean DEFAULT false,
    exibir_painel_flutuante boolean DEFAULT true,
    descricao_perfil character varying(200),
    ocultar_data_criacao boolean DEFAULT false,
    dias_semana_bloqueados integer[] DEFAULT '{}'::integer[],
    limitar_parcelas_pelo_evento boolean DEFAULT false NOT NULL,
    cover_image_url text,
    footer_image_url text,
    CONSTRAINT chk_layout_produtos CHECK ((layout_produtos = ANY (ARRAY['lista'::text, 'grid'::text]))),
    CONSTRAINT chk_tamanho_imagem_grid CHECK ((tamanho_imagem_grid = ANY (ARRAY['pequeno'::text, 'medio'::text, 'grande'::text]))),
    CONSTRAINT templates_tema_check CHECK ((tema = ANY (ARRAY['moderno'::text, 'classico'::text, 'romantico'::text, 'vibrante'::text, 'natural'::text, 'minimalista'::text, 'pretoebranco'::text, 'escuro'::text, 'studio'::text, 'darkstudio'::text, 'promocional'::text, 'oferta'::text, 'pdf-elegante'::text])))
);


--
-- Name: COLUMN templates.uuid; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.uuid IS 'Public UUID for template access via URLs';


--
-- Name: COLUMN templates.bloquear_campos_obrigatorios; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.bloquear_campos_obrigatorios IS 'Quando TRUE, bloqueia produtos extras e WhatsApp até preencher campos obrigatórios';


--
-- Name: COLUMN templates.sistema_sazonal_ativo; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.sistema_sazonal_ativo IS 'Enable/disable seasonal pricing adjustments (date-based pricing)';


--
-- Name: COLUMN templates.sistema_geografico_ativo; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.sistema_geografico_ativo IS 'Enable/disable geographic pricing adjustments (cities, states, countries)';


--
-- Name: COLUMN templates.tema; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.tema IS 'Tema visual da página de orçamento: moderno (azul/clean), classico (preto/dourado), romantico (rosa/lavanda), vibrante (roxo/laranja), escuro (modo dark), natural (verde/âmbar), minimalista (cinza/espaços amplos), studio (rose/bronze)';


--
-- Name: COLUMN templates.slug_template; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.slug_template IS 'Slug único do template dentro do escopo do usuário';


--
-- Name: COLUMN templates.exibir_no_perfil; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.exibir_no_perfil IS 'Define se o template aparece no perfil público';


--
-- Name: COLUMN templates.ordem_exibicao; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.ordem_exibicao IS 'Ordem customizada de exibição do template no dashboard e perfil público';


--
-- Name: COLUMN templates.layout_produtos; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.layout_produtos IS 'Define o layout de exibição dos produtos no orçamento (ex: "grid", "lista").';


--
-- Name: COLUMN templates.tamanho_imagem_grid; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.tamanho_imagem_grid IS 'Define o tamanho das imagens no layout grid (ex: "pequeno", "medio", "grande").';


--
-- Name: COLUMN templates.layout_produtos_desktop; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.layout_produtos_desktop IS 'Controla o layout dos produtos na página de orçamento (ex: linha, quadro).';


--
-- Name: COLUMN templates.whatsapp_followup_mostra_valores_individuais; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.whatsapp_followup_mostra_valores_individuais IS 'Controla se os valores individuais dos produtos são mostrados na mensagem de follow-up do WhatsApp para leads. É independente da configuração "ocultar_valores_intermediarios".';


--
-- Name: COLUMN templates.forma_pagamento_obrigatoria; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.forma_pagamento_obrigatoria IS 'Quando ativo, o cliente é obrigado a selecionar uma forma de pagamento antes de enviar o orçamento. Só tem efeito se o template tiver formas de pagamento cadastradas.';


--
-- Name: COLUMN templates.limitar_parcelas_pelo_evento; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.templates.limitar_parcelas_pelo_evento IS 'Quando ativo, o limite máximo de parcelas é dinamicamente reduzido de acordo com a quantidade de meses restantes até a data do evento selecionado.';


