eb81f4ce-c142-4040-8c6c-c2d275ed3c17	e1c0ca56-d6bb-44cc-ae98-eeee513de9fb	c5658132-1f86-4e87-9504-f8ebded28d46	abandonado	2026-04-29 12:11:42.835267+00	2026-04-29 12:11:42.835267+00	{}	\N	\N	\N	Joana Alves da Silva	joanaalvesdasilva440@gmail.com	92984961754	Casamentos	2026-05-02		2200.00	{"produtos": [{"id": "88ed0d6b-75a1-44c5-ac94-bf18a53d2845", "nome": "💍 Cobertura de Casamento (sem recepção)", "ordem": 0, "valor": 2200, "imagem": null, "resumo": "Registro completo da cerimônia, com foco nas emoções, detalhes e momentos espontâneos do casal e convidados. Ensaio do casal de pós casamento no local do evento após a finalização da cerimônia (aproximadamente 1h de ensaio). Ideal para casamentos, somente celebração (religiosa na igreja ou ao ar livre, mini weddings). (2 FOTÓGRAFOS)\\nATENÇÃO, Este serviço não INCLUI:\\n- Ensaio de pré casamento (NÃO INCLUSO);\\n- Making of do noivo (NÃO INCLUSO);\\n- Making of da noiva  (NÃO INCLUSO);\\n- Recepção  (NÃO INCLUSO);\\n- Álbum  (NÃO INCLUSO);\\n- Quadro  (NÃO INCLUSO);\\nPARA ACRESCENTAR AO SEU PACOTE, BASTA SELECIONAR OS ADICIONAIS LOGO ABAIXO.", "imagens": [], "unidade": "pacote", "user_id": null, "created_at": "2026-03-26T18:57:25.945625", "imagem_url": null, "updated_at": "2026-03-26T18:57:25.945625+00:00", "obrigatorio": true, "template_id": "c5658132-1f86-4e87-9504-f8ebded28d46", "mostrar_imagem": true, "carrossel_automatico": false}, {"id": "b3a63977-9f6f-4f3a-8ed1-9e324f52dc63", "nome": "1 HORA de Cobertura de Recepção", "ordem": 1, "valor": 250, "imagem": null, "resumo": "Total de 1 hora de Cobertura da festa, nossa equipe estará presente durante 1 hora do seu evento para fotografar dentro do tempo contratado. Este pacote já é ideal para recepção de eventos PEQUENAS/SIMPLES/MINIWEDDING (1 fotógrafo).", "imagens": [], "unidade": "pacote", "user_id": null, "created_at": "2026-03-26T18:57:26.387366", "imagem_url": null, "updated_at": "2026-03-26T18:57:26.387366+00:00", "obrigatorio": false, "template_id": "c5658132-1