COPY supabase_migrations.schema_migrations (version, statements, name) FROM stdin;
20251120000000	{"/*\n  # Sistema de Notificações\n\n  ## Objetivo\n  Criar tabela de notificações para o sistema Priceus, permitindo notificações personalizadas\n  para usuários sobre eventos importantes da plataforma.\n\n  ## Tabela Criada\n\n  ### notifications\n  - Notificações personalizadas para usuários\n  - Tipos: info, warning, success, error, trial\n  - Controle de leitura\n  - Dados adicionais opcionais em JSON\n\n  ## Segurança\n  - RLS habilitado\n  - Usuários só acessam suas próprias notificações\n*/\n\n-- =============================================\n-- TABELA DE NOTIFICAÇÕES (SCRIPT IDEMPOTENTE)\n-- =============================================\nCREATE TABLE IF NOT EXISTS notifications (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,\n  created_at timestamptz DEFAULT now()\n)","DO $$\nBEGIN\n  -- Adicionar colunas se não existirem\n  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='notifications' AND column_name='title') THEN\n    ALTER TABLE notifications ADD COLUMN title text NOT NULL;\n  END IF;\n  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='notifications' AND column_name='message') THEN\n    ALTER TABLE notifications ADD COLUMN message text NOT NULL;\n  END IF;\n  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='notifications' AND column_name='type') THEN\n    ALTER TABLE notifications ADD COLUMN type text NOT NULL DEFAULT 'info';\n  END IF;\n  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='notifications' AND column_name='read') THEN\n    ALTER TABLE notifications ADD COLUMN read boolean DEFAULT false;\n  END IF;\n  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='notifications' AND column_name='data') THEN\n    ALTER TABLE notifications ADD COLUMN data jsonb;\n  END IF;\n  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='notifications' AND column_name='updated_at') THEN\n    ALTER TABLE notifications ADD COLUMN updated_at timestamptz DEFAULT now();\n  END IF;\n\n  -- Adicionar a restrição CHECK se não existir\n  IF NOT EXISTS (SELECT 1 FROM information_schema.constraint_column_usage where table_name='notifications' and constraint_name='notifications_type_check') THEN\n    ALTER TABLE notifications ADD CONSTRAINT notifications_type_check CHECK (type IN ('info', 'warning', 'success', 'error', 'trial'));\n  END IF;\nEND $$","-- Índices para performance\nCREATE INDEX IF NOT EXISTS idx_notifications_user_id ON notifications(user_id)","CREATE INDEX IF NOT EXISTS idx_notifications_read ON notifications(read)","CREATE INDEX IF NOT EXISTS idx_notifications_type ON notifications(type)","CREATE INDEX IF NOT EXISTS idx_notifications_created_at ON notifications(created_at DESC)","-- RLS\nALTER TABLE notifications ENABLE ROW LEVEL SECURITY","-- Política: Usuários podem ver suas próprias notificações\nCREATE POLICY \\"Users can view own notifications\\"\n  ON notifications FOR SELECT\n  TO authenticated\n  USING (auth.uid() = user_id)","-- Política: Sistema pode inserir notificações (para funções)\nCREATE POLICY \\"System can insert notifications\\"\n  ON notifications FOR INSERT\n  TO authenticated\n  WITH CHECK (true)","-- Política: Usuários podem atualizar suas próprias notificações (marcar como lida)\nCREATE POLICY \\"Users can update own notifications\\"\n  ON notifications FOR UPDATE\n  TO authenticated\n  USING (auth.uid() = user_id)\n  WITH CHECK (auth.uid() = user_id)","-- Política: Usuários podem deletar suas próprias notificações\nCREATE POLICY \\"Users can delete own notifications\\"\n  ON notifications FOR DELETE\n  TO authenticated\n  USING (auth.uid() = user_id)","-- =============================================\n-- TRIGGER PARA UPDATED_AT\n-- =============================================\nCREATE OR REPLACE FUNCTION update_notifications_updated_at()\nRETURNS TRIGGER AS $$\nBEGIN\n  NEW.updated_at = now();\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql","DROP TRIGGER IF EXISTS update_notifications_updated_at_trigger ON notifications","CREATE TRIGGER update_notifications_updated_at_trigger\n  BEFORE UPDATE ON notifications\n  FOR EACH ROW\n  EXECUTE FUNCTION update_notifications_updated_at()","-- =============================================\n-- FUNÇÃO PARA MARCAR NOTIFICAÇÃO COMO LIDA\n-- =============================================\nCREATE OR REPLACE FUNCTION mark_notification_as_read(notification_id_param uuid)\nRETURNS boolean AS $$\nBEGIN\n  UPDATE notifications\n  SET read = true, updated_at = now()\n  WHERE id = notification_id_param\n    AND user_id = auth.uid();\n\n  RETURN FOUND;\nEND;\n$$ LANGUAGE plpgsql SECURITY DEFINER","-- =============================================\n-- FUNÇÃO PARA MARCAR TODAS AS NOTIFICAÇÕES COMO LIDAS\n-- =============================================\nCREATE OR REPLACE FUNCTION mark_all_notifications_as_read()\nRETURNS integer AS $$\nDECLARE\n  updated_count integer;\nBEGIN\n  UPDATE notifications\n  SET read = true, updated_at = now()\n  WHERE user_id = auth.uid()\n    AND read = false;\n\n  GET DIAGNOSTICS updated_count = ROW_COUNT;\n  RETURN updated_count;\nEND;\n$$ LANGUAGE plpgsql SECURITY DEFINER","-- =============================================\n-- FUNÇÃO PARA CRIAR NOTIFICAÇÃO\n-- =============================================\nCREATE OR REPLACE FUNCTION create_notification(\n  user_id_param uuid,\n  title_param text,\n  message_param text,\n  type_param text DEFAULT 'info',\n  data_param jsonb DEFAULT NULL\n)\nRETURNS uuid AS $$\nDECLARE\n  notification_id uuid;\nBEGIN\n  INSERT INTO notifications (user_id, title, message, type, data)\n  VALUES (user_id_param, title_param, message_param, type_param, data_param)\n  RETURNING id INTO notification_id;\n\n  RETURN notification_id;\nEND;\n$$ LANGUAGE plpgsql SECURITY DEFINER"}	create_notifications_table
20251105060000	{"-- Adiciona a coluna texto_botao_envio na tabela templates se não existir\nALTER TABLE public.templates \nADD COLUMN IF NOT EXISTS texto_botao_envio text DEFAULT 'Negociar no WhatsApp'","-- Garante que a coluna tema existe\nALTER TABLE public.templates \nADD COLUMN IF NOT EXISTS tema text DEFAULT 'moderno'"}	fix_template_schema
20260302000000	{"-- supabase/migrations/create_analytics_orcamentos_table.sql\n\n-- =============================================\n-- Criar tabela de analytics para orçamentos\n-- =============================================\n\n-- Criar tabela se não existir\nCREATE TABLE IF NOT EXISTS analytics_orcamentos (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    template_id UUID REFERENCES templates(id) ON DELETE CASCADE,\n    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE,\n    session_id TEXT NOT NULL,\n    origem TEXT DEFAULT 'web',\n    referrer TEXT,\n    device_type TEXT DEFAULT 'desktop',\n    user_agent TEXT,\n    utm_source TEXT,\n    utm_campaign TEXT,\n    ultima_etapa TEXT DEFAULT 'inicio',\n    campos_preenchidos JSONB DEFAULT '{}',\n    produtos_visualizados TEXT[] DEFAULT '{}',\n    interacoes INTEGER DEFAULT 0,\n    scroll_profundidade INTEGER DEFAULT 0,\n    tempo_permanencia INTEGER DEFAULT 0,\n    orcamento_enviado BOOLEAN DEFAULT false,\n    abandonou BOOLEAN DEFAULT false,\n    tempo_ate_abandono INTEGER,\n    created_at TIMESTAMPTZ DEFAULT NOW(),\n    updated_at TIMESTAMPTZ DEFAULT NOW()\n)","-- Habilitar RLS\nALTER TABLE analytics_orcamentos ENABLE ROW LEVEL SECURITY","-- Grant permissions\nGRANT ALL ON analytics_orcamentos TO authenticated","GRANT SELECT, INSERT ON analytics_orcamentos TO anon","GRANT SELECT, INSERT, UPDATE ON analytics_orcamentos TO authenticated","-- Criar políticas RLS\nDROP POLICY IF EXISTS \\"Allow anon insert analytics\\" ON analytics_orcamentos","DROP POLICY IF EXISTS \\"Owner read analytics\\" ON analytics_orcamentos","CREATE POLICY \\"Allow anon insert analytics\\" \nON analytics_orcamentos \nFOR INSERT \nTO anon, authenticated \nWITH CHECK (true)","CREATE POLICY \\"Owner read analytics\\" \nON analytics_orcamentos \nFOR SELECT \nTO authenticated \nUSING (auth.uid() = user_id)","CREATE POLICY \\"Owner update analytics\\" \nON analytics_orcamentos \nFOR UPDATE \nTO authenticated \nUSING (auth.uid() = user_id) \nWITH CHECK (auth.uid() = user_id)","-- Criar índices para performance\nCREATE INDEX IF NOT EXISTS idx_analytics_session ON analytics_orcamentos(session_id)","CREATE INDEX IF NOT EXISTS idx_analytics_user ON analytics_orcamentos(user_id)","CREATE INDEX IF NOT EXISTS idx_analytics_template ON analytics_orcamentos(template_id)","CREATE INDEX IF NOT EXISTS idx_analytics_created ON analytics_orcamentos(created_at)","-- Adicionar trigger para updated_at automático\nCREATE OR REPLACE FUNCTION update_updated_at_column()\nRETURNS TRIGGER AS $$\nBEGIN\n    NEW.updated_at = NOW();\n    RETURN NEW;\nEND;\n$$ language 'plpgsql'","DROP TRIGGER IF EXISTS update_analytics_updated_at ON analytics_orcamentos","CREATE TRIGGER update_analytics_updated_at \nBEFORE UPDATE ON analytics_orcamentos \nFOR EACH ROW \nEXECUTE FUNCTION update_updated_at_column()","COMMENT ON TABLE analytics_orcamentos IS 'Tabela para analytics de orçamentos - tracking de comportamento do usuário'"}	create_analytics_orcamentos
20260302000001	{"-- supabase/migrations/fix_configuracao_agenda_rls.sql\n\n-- =============================================\n-- Correção: Policy RLS para configuracao_agenda\n-- Permite leitura anônima para usuários não autenticados\n-- =============================================\n\n-- 1. Primeiro, verificar se a tabela existe\nDO $$ \nBEGIN\n    IF EXISTS (\n        SELECT FROM information_schema.tables \n        WHERE table_schema = 'public' \n        AND table_name = 'configuracao_agenda'\n    ) THEN\n        -- Drop existing policies that might block access\n        DROP POLICY IF EXISTS \\"Allow public read access\\" ON configuracao_agenda;\n        DROP POLICY IF EXISTS \\"Allow anon read\\" ON configuracao_agenda;\n        DROP POLICY IF EXISTS \\"Allow authenticated insert\\" ON configuracao_agenda;\n        \n        -- 2. Criar política para permitir leitura anônima (necessário para página pública de orçamento)\n        CREATE POLICY \\"Allow anon read configuracao_agenda\\" \n        ON configuracao_agenda \n        FOR SELECT \n        TO anon, authenticated \n        USING (true);\n        \n        -- 3. Criar política para permitir inserção apenas para usuários autenticados\n        CREATE POLICY \\"Allow authenticated insert configuracao_agenda\\" \n        ON configuracao_agenda \n        FOR INSERT \n        TO authenticated \n        WITH CHECK (auth.uid() = user_id);\n        \n        -- 4. Criar política para permitir atualização apenas pelo dono\n        CREATE POLICY \\"Allow owner update configuracao_agenda\\" \n        ON configuracao_agenda \n        FOR UPDATE \n        TO authenticated \n        USING (auth.uid() = user_id) \n        WITH CHECK (auth.uid() = user_id);\n        \n        RAISE NOTICE 'Policies created successfully for configuracao_agenda';\n    ELSE\n        RAISE WARNING 'Table configuracao_agenda does not exist';\n    END IF;\nEND $$","-- =============================================\n-- Também criar a tabela se não existir (backup)\n-- =============================================\nCREATE TABLE IF NOT EXISTS configuracao_agenda (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,\n    eventos_max_por_dia INTEGER DEFAULT 1,\n    modo_aviso TEXT DEFAULT 'sugestivo' CHECK (modo_aviso IN ('informativo', 'sugestivo', 'restritivo')),\n    agenda_ativa BOOLEAN DEFAULT true,\n    created_at TIMESTAMPTZ DEFAULT NOW(),\n    updated_at TIMESTAMPTZ DEFAULT NOW(),\n    UNIQUE(user_id)\n)","-- Habilitar RLS\nALTER TABLE configuracao_agenda ENABLE ROW LEVEL SECURITY","-- Grant permissions\nGRANT ALL ON configuracao_agenda TO authenticated","GRANT SELECT ON configuracao_agenda TO anon","GRANT INSERT, UPDATE ON configuracao_agenda TO authenticated"}	fix_configuracao_agenda_rls
20260302000002	{"-- =====================================================\n-- CRIAR BUCKETS E POLÍTICAS PARA SUPABASE\n-- Execute este SQL no Supabase Dashboard > SQL Editor\n-- =====================================================\n\n-- 1. Verificar buckets existentes (para diagnóstico)\nSELECT id, name, public, file_size_limit, allowed_mime_types \nFROM storage.buckets","-- =====================================================\n-- CRIAR BUCKET 'IMAGES'\n-- =====================================================\n\n-- Criar bucket images (público)\nINSERT INTO storage.buckets (id, name, public)\nVALUES ('images', 'images', true)\nON CONFLICT (id) DO NOTHING","-- Políticas para bucket 'images' (usar DROP IF EXISTS para evitar erros)\n\n-- Upload (INSERT) - usuários autenticados podem fazer upload\nDROP POLICY IF EXISTS \\"images_allow_uploads\\" ON storage.objects","CREATE POLICY \\"images_allow_uploads\\"\nON storage.objects FOR INSERT\nTO authenticated\nWITH CHECK (\n  bucket_id = 'images'\n  AND (storage.foldername(name))[1] IN ('produtos', 'uploads', 'thumbnails', 'temp')\n)","-- Update - usuários autenticados podem atualizar\nDROP POLICY IF EXISTS \\"images_allow_updates\\" ON storage.objects","CREATE POLICY \\"images_allow_updates\\"\nON storage.objects FOR UPDATE\nTO authenticated\nUSING (bucket_id = 'images')\nWITH CHECK (bucket_id = 'images')","-- Delete - usuários autenticados podem deletar\nDROP POLICY IF EXISTS \\"images_allow_deletes\\" ON storage.objects","CREATE POLICY \\"images_allow_deletes\\"\nON storage.objects FOR DELETE\nTO authenticated\nUSING (\n  bucket_id = 'images'\n  AND (storage.foldername(name))[1] IN ('produtos', 'uploads', 'thumbnails', 'temp')\n)","-- Select - todos podem ler (público)\nDROP POLICY IF EXISTS \\"images_public_read\\" ON storage.objects","CREATE POLICY \\"images_public_read\\"\nON storage.objects FOR SELECT\nUSING (bucket_id = 'images')","-- =====================================================\n-- CRIAR BUCKET 'CONTRACT-PDFS'\n-- =====================================================\n\n-- Criar bucket contract-pdfs (público)\nINSERT INTO storage.buckets (id, name, public)\nVALUES ('contract-pdfs', 'contract-pdfs', true)\nON CONFLICT (id) DO NOTHING","-- Políticas para bucket 'contract-pdfs'\n\n-- Upload - usuários autenticados e públicos podem fazer upload\nDROP POLICY IF EXISTS \\"contract_pdfs_allow_uploads\\" ON storage.objects","CREATE POLICY \\"contract_pdfs_allow_uploads\\"\nON storage.objects FOR INSERT\nTO authenticated\nWITH CHECK (bucket_id = 'contract-pdfs')","-- Upload público para clientes que assinam\nDROP POLICY IF EXISTS \\"contract_pdfs_public_uploads\\" ON storage.objects","CREATE POLICY \\"contract_pdfs_public_uploads\\"\nON storage.objects FOR INSERT\nTO public\nWITH CHECK (bucket_id = 'contract-pdfs')","-- Update\nDROP POLICY IF EXISTS \\"contract_pdfs_allow_updates\\" ON storage.objects","CREATE POLICY \\"contract_pdfs_allow_updates\\"\nON storage.objects FOR UPDATE\nTO authenticated\nUSING (bucket_id = 'contract-pdfs')\nWITH CHECK (bucket_id = 'contract-pdfs')","-- Delete - apenas dono pode deletar\nDROP POLICY IF EXISTS \\"contract_pdfs_allow_deletes\\" ON storage.objects","CREATE POLICY \\"contract_pdfs_allow_deletes\\"\nON storage.objects FOR DELETE\nTO authenticated\nUSING (\n  bucket_id = 'contract-pdfs'\n  AND (storage.foldername(name))[1] = auth.uid()::text\n)","-- Select público\nDROP POLICY IF EXISTS \\"contract_pdfs_public_read\\" ON storage.objects","CREATE POLICY \\"contract_pdfs_public_read\\"\nON storage.objects FOR SELECT\nUSING (bucket_id = 'contract-pdfs')","-- =====================================================\n-- CRIAR BUCKET 'PROFILE_IMAGES'\n-- =====================================================\n\n-- Criar bucket profile_images (público)\nINSERT INTO storage.buckets (id, name, public)\nVALUES ('profile_images', 'profile_images', true)\nON CONFLICT (id) DO NOTHING","-- Políticas para bucket 'profile_images'\n\n-- Upload\nDROP POLICY IF EXISTS \\"profile_images_allow_uploads\\" ON storage.objects","CREATE POLICY \\"profile_images_allow_uploads\\"\nON storage.objects FOR INSERT\nTO authenticated\nWITH CHECK (\n  bucket_id = 'profile_images'\n  AND (storage.foldername(name))[1] = auth.uid()::text\n)","-- Update\nDROP POLICY IF EXISTS \\"profile_images_allow_updates\\" ON storage.objects","CREATE POLICY \\"profile_images_allow_updates\\"\nON storage.objects FOR UPDATE\nTO authenticated\nUSING (\n  bucket_id = 'profile_images'\n  AND (storage.foldername(name))[1] = auth.uid()::text\n)\nWITH CHECK (\n  bucket_id = 'profile_images'\n  AND (storage.foldername(name))[1] = auth.uid()::text\n)","-- Delete\nDROP POLICY IF EXISTS \\"profile_images_allow_deletes\\" ON storage.objects","CREATE POLICY \\"profile_images_allow_deletes\\"\nON storage.objects FOR DELETE\nTO authenticated\nUSING (\n  bucket_id = 'profile_images'\n  AND (storage.foldername(name))[1] = auth.uid()::text\n)","-- Select público\nDROP POLICY IF EXISTS \\"profile_images_public_read\\" ON storage.objects","CREATE POLICY \\"profile_images_public_read\\"\nON storage.objects FOR SELECT\nUSING (bucket_id = 'profile_images')","-- =====================================================\n-- VERIFICAR RESULTADO\n-- =====================================================\n\n-- Listar buckets criados\nSELECT id, name, public, file_size_limit, allowed_mime_types \nFROM storage.buckets","-- Listar políticas criadas\nSELECT policyname, cmd, schemaname, tablename\nFROM pg_policies \nWHERE schemaname = 'storage'\nAND tablename = 'objects'\nORDER BY policyname","-- Forçar recarregamento de políticas\nNOTIFY storage_objects, 'reload'"}	create_buckets
20260302000003	{"-- =====================================================\n-- SUPABASE STORAGE FIX - UPLOAD DE IMAGENS\n-- Execute este SQL no Supabase Dashboard > SQL Editor\n-- =====================================================\n\n-- 1. Verificar buckets existentes\nSELECT id, name, public, file_size_limit, allowed_mime_types \nFROM storage.buckets","-- 2. Verificar políticas existentes\nSELECT policyname, cmd, qual, with_check \nFROM pg_policies \nWHERE schemaname = 'storage' \nAND tablename = 'objects'","-- 3. Remover políticas problemáticas do bucket 'images' (se existirem)\nDROP POLICY IF EXISTS \\"Allow authenticated uploads\\" ON storage.objects","DROP POLICY IF EXISTS \\"Allow public access\\" ON storage.objects","DROP POLICY IF EXISTS \\"images_authenticated_delete\\" ON storage.objects","DROP POLICY IF EXISTS \\"images_authenticated_update\\" ON storage.objects","DROP POLICY IF EXISTS \\"images_authenticated_upload\\" ON storage.objects","DROP POLICY IF EXISTS \\"images_public_read\\" ON storage.objects","-- 4. Criar políticas atualizadas para o bucket 'images'\n-- Política: Qualquer usuário autenticado pode fazer upload\nDROP POLICY IF EXISTS \\"images_allow_uploads\\" ON storage.objects","CREATE POLICY \\"images_allow_uploads\\"\nON storage.objects FOR INSERT\nTO authenticated\nWITH CHECK (\n  bucket_id = 'images'\n  AND (storage.foldername(name))[1] IN ('produtos', 'uploads', 'thumbnails', 'temp')\n)","-- Política: Qualquer usuário autenticado pode atualizar\nDROP POLICY IF EXISTS \\"images_allow_updates\\" ON storage.objects","CREATE POLICY \\"images_allow_updates\\"\nON storage.objects FOR UPDATE\nTO authenticated\nUSING (bucket_id = 'images')\nWITH CHECK (bucket_id = 'images')","-- Política: Qualquer usuário autenticado pode deletar\nDROP POLICY IF EXISTS \\"images_allow_deletes\\" ON storage.objects","CREATE POLICY \\"images_allow_deletes\\"\nON storage.objects FOR DELETE\nTO authenticated\nUSING (\n  bucket_id = 'images'\n  AND (storage.foldername(name))[1] IN ('produtos', 'uploads', 'thumbnails', 'temp')\n)","-- Política: Todos podem ler (público)\nDROP POLICY IF EXISTS \\"images_public_read\\" ON storage.objects","CREATE POLICY \\"images_public_read\\"\nON storage.objects FOR SELECT\nUSING (bucket_id = 'images')","-- 5. Forçar recarregamento de políticas\nNOTIFY storage_objects, 'reload'","-- 6. Testar upload - listar objetos no bucket\nSELECT id, bucket_id, name, created_at \nFROM storage.objects \nWHERE bucket_id = 'images' \nORDER BY created_at DESC \nLIMIT 10","-- 7. Verificar se há registros órfãos no storage\nSELECT id, bucket_id, name, created_at \nFROM storage.objects \nWHERE bucket_id NOT IN (SELECT id FROM storage.buckets)","-- 8. Contar arquivos por bucket\nSELECT \n  bucket_id,\n  COUNT(*) as file_count\nFROM storage.objects \nGROUP BY bucket_id"}	fix_storage_policies
20260302000004	{"-- Verificar se a tabela leads já existe\nDO $$ \nBEGIN\n    IF NOT EXISTS (SELECT FROM information_schema.tables WHERE table_name = 'leads') THEN\n        -- Criar tabela de leads (sem FK obrigatória para templates)\n        CREATE TABLE leads (\n            id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n            template_id UUID,  -- UUID do template (sem FK para evitar erros)\n            user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE,\n            \n            -- Dados do Cliente (novos nomes de campos)\n            client_name TEXT,\n            client_email TEXT,\n            client_phone TEXT,\n            \n            -- Dados do Cliente (nomes antigos para compatibilidade)\n            nome_cliente TEXT,\n            email_cliente TEXT,\n            telefone_cliente TEXT,\n            \n            -- Dados do Evento\n            tipo_evento TEXT,\n            data_evento DATE,\n            cidade_evento TEXT,\n            \n            -- Orçamento\n            valor_total NUMERIC(10,2) DEFAULT 0,\n            orcamento_detalhes JSONB DEFAULT '{}',\n            url_origem TEXT,\n            \n            -- Status e Tracking\n            status TEXT DEFAULT 'novo',\n            origem TEXT DEFAULT 'web',\n            session_id TEXT,\n            user_agent TEXT,\n            tempo_preenchimento_segundos INTEGER,\n            \n            -- Campos LGPD\n            lgpd_consent_timestamp TIMESTAMPTZ,\n            lgpd_consent_text TEXT,\n            \n            -- Timestamps\n            created_at TIMESTAMPTZ DEFAULT NOW(),\n            updated_at TIMESTAMPTZ DEFAULT NOW()\n        );\n        \n        -- Habilitar RLS\n        ALTER TABLE leads ENABLE ROW LEVEL SECURITY;\n        \n        -- Políticas RLS\n        CREATE POLICY \\"Users can view own leads\\" ON leads\n            FOR SELECT\n            USING (auth.uid() = user_id);\n\n        CREATE POLICY \\"Users can insert leads\\" ON leads\n            FOR INSERT\n            WITH CHECK (auth.uid() = user_id);\n\n        CREATE POLICY \\"Users can update own leads\\" ON leads\n            FOR UPDATE\n            USING (auth.uid() = user_id);\n\n        CREATE POLICY \\"Users can delete own leads\\" ON leads\n            FOR DELETE\n            USING (auth.uid() = user_id);\n        \n        -- Índices para performance\n        CREATE INDEX IF NOT EXISTS idx_leads_user_id ON leads(user_id);\n        CREATE INDEX IF NOT EXISTS idx_leads_status ON leads(status);\n        CREATE INDEX IF NOT EXISTS idx_leads_created_at ON leads(created_at DESC);\n        \n        -- Comentário\n        COMMENT ON TABLE leads IS 'Tabela de captura de leads e orçamentos';\n    END IF;\nEND $$","-- Comentário para documentação\nCOMMENT ON COLUMN leads.status IS 'Status do lead: novo, abandonado, contatado, convertido, perdido'"}	create_leads_table
20260302000005	{"-- Corrigir nome do campo orcamento_detalhes para orcamento_detalhe (singular)\n-- para manter consistência com o código frontend\n\n-- Verificar se a coluna orcamento_detalhe já existe\nDO $$ \nBEGIN\n    -- Se existir a coluna com nome plural, renomear para singular\n    IF EXISTS (SELECT FROM information_schema.columns \n               WHERE table_name = 'leads' AND column_name = 'orcamento_detalhes') THEN\n        ALTER TABLE leads RENAME COLUMN orcamento_detalhes TO orcamento_detalhe;\n    END IF;\n    \n    -- Se não existir nenhuma das duas, criar com nome correto\n    IF NOT EXISTS (SELECT FROM information_schema.columns \n                   WHERE table_name = 'leads' AND column_name = 'orcamento_detalhe') THEN\n        ALTER TABLE leads ADD COLUMN orcamento_detalhe JSONB DEFAULT '{}';\n    END IF;\nEND $$"}	fix_leads_campo_orcamento
20260309000000	{"-- Adicionar campos extras à tabela leads se não existirem\nDO $$ \nBEGIN\n    -- Adicionar campos de evento se não existirem\n    IF NOT EXISTS (SELECT FROM information_schema.columns WHERE table_name = 'leads' AND column_name = 'data_evento') THEN\n        ALTER TABLE leads ADD COLUMN data_evento DATE;\n    END IF;\n    \n    IF NOT EXISTS (SELECT FROM information_schema.columns WHERE table_name = 'leads' AND column_name = 'cidade_evento') THEN\n        ALTER TABLE leads ADD COLUMN cidade_evento TEXT;\n    END IF;\n    \n    IF NOT EXISTS (SELECT FROM information_schema.columns WHERE table_name = 'leads' AND column_name = 'tipo_evento') THEN\n        ALTER TABLE leads ADD COLUMN tipo_evento TEXT;\n    END IF;\n    \n    -- Adicionar campo de dados do formulário se não existir\n    IF NOT EXISTS (SELECT FROM information_schema.columns WHERE table_name = 'leads' AND column_name = 'dados_formulario') THEN\n        ALTER TABLE leads ADD COLUMN dados_formulario JSONB DEFAULT '{}';\n    END IF;\n    \n    -- Adicionar campo de origem se não existir\n    IF NOT EXISTS (SELECT FROM information_schema.columns WHERE table_name = 'leads' AND column_name = 'url_origem') THEN\n        ALTER TABLE leads ADD COLUMN url_origem TEXT;\n    END IF;\nEND $$","-- Comentários para documentação\nCOMMENT ON COLUMN leads.data_evento IS 'Data do evento selecionado pelo cliente'","COMMENT ON COLUMN leads.cidade_evento IS 'Cidade do evento selecionado pelo cliente'","COMMENT ON COLUMN leads.tipo_evento IS 'Tipo de evento (ex: casamento,formatura)'","COMMENT ON COLUMN leads.dados_formulario IS 'Dados completos do formulário em JSON'","COMMENT ON COLUMN leads.url_origem IS 'URL de origem do lead'"}	add_leads_extra_fields
20260310000000	{"-- Migração para corrigir a tabela de notifications\n-- Problema: O código frontend usa is_read, link, related_id mas a tabela usa read, title, data\n\n-- 1. Adicionar colunas que faltam (se não existirem)\n-- Migração para corrigir a tabela de notifications\n-- Versão simplificada - garante índices e políticas RLS corretos\n\n-- Criar índice para o campo is_read (se não existir)\nCREATE INDEX IF NOT EXISTS idx_notifications_is_read ON notifications(is_read)","-- Atualizar políticas RLS\nDROP POLICY IF EXISTS \\"Users can view own notifications\\" ON notifications","CREATE POLICY \\"Users can view own notifications\\"\n  ON notifications FOR SELECT\n  TO authenticated\n  USING (auth.uid() = user_id)","DROP POLICY IF EXISTS \\"Users can update own notifications\\" ON notifications","CREATE POLICY \\"Users can update own notifications\\"\n  ON notifications FOR UPDATE\n  TO authenticated\n  USING (auth.uid() = user_id)\n  WITH CHECK (auth.uid() = user_id)"}	fix_notifications_schema
20260310000001	{"-- =============================================\n-- MIGRAÇÃO COMPLETA PARA CORRIGIR TABELA DE NOTIFICATIONS\n-- Problema: Código usa is_read, link, related_id mas tabela tem read, title, data\n-- =============================================\n\n-- 1. Adicionar coluna is_read se não existir (mapear de read)\nDO $$ \nBEGIN\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'notifications' AND column_name = 'is_read') THEN\n        ALTER TABLE notifications ADD COLUMN is_read boolean DEFAULT false;\n        -- Copiar dados de read para is_read\n        UPDATE notifications SET is_read = read WHERE is_read IS NULL OR is_read = false;\n    END IF;\nEND $$","-- 2. Adicionar coluna link se não existir\nDO $$ \nBEGIN\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'notifications' AND column_name = 'link') THEN\n        ALTER TABLE notifications ADD COLUMN link text;\n    END IF;\nEND $$","-- 3. Adicionar coluna related_id se não existir\nDO $$ \nBEGIN\n    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'notifications' AND column_name = 'related_id') THEN\n        ALTER TABLE notifications ADD COLUMN related_id uuid;\n    END IF;\nEND $$","-- 4. Remover coluna title se não for necessária (manter para compatibilidade)\n-- A tabela original tinha title, mas o código novo usa só message\n\n-- 5. Criar índice para performance\nCREATE INDEX IF NOT EXISTS idx_notifications_is_read ON notifications(is_read)","CREATE INDEX IF NOT EXISTS idx_notifications_related_id ON notifications(related_id)","-- 6. Atualizar políticas RLS\nDROP POLICY IF EXISTS \\"Users can view own notifications\\" ON notifications","CREATE POLICY \\"Users can view own notifications\\"\n  ON notifications FOR SELECT\n  TO authenticated\n  USING (auth.uid() = user_id)","DROP POLICY IF EXISTS \\"Users can update own notifications\\" ON notifications","CREATE POLICY \\"Users can update own notifications\\"\n  ON notifications FOR UPDATE\n  TO authenticated\n  USING (auth.uid() = user_id)\n  WITH CHECK (auth.uid() = user_id)","-- 7. Garantir que anon e service_role possam inserir via functions\nDROP POLICY IF EXISTS \\"System can insert notifications\\" ON notifications","CREATE POLICY \\"System can insert notifications\\"\n  ON notifications FOR INSERT\n  TO authenticated\n  WITH CHECK (true)","-- 8. Atualizar trigger de updated_at (se necessário)\nCREATE OR REPLACE FUNCTION update_notifications_updated_at()\nRETURNS TRIGGER AS $$\nBEGIN\n  NEW.updated_at = now();\n  RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql","DROP TRIGGER IF EXISTS update_notifications_updated_at_trigger ON notifications","CREATE TRIGGER update_notifications_updated_at_trigger\n  BEFORE UPDATE ON notifications\n  FOR EACH ROW\n  EXECUTE FUNCTION update_notifications_updated_at()","-- 9. Criar view para compatibilidade (opcional - mapeia read para is_read)\n-- DROP VIEW IF EXISTS notifications_view;\n-- CREATE VIEW notifications_view AS\n-- SELECT \n--   id,\n--   user_id,\n--   COALESCE(title, message) as title,\n--   message,\n--   type,\n--   COALESCE(read, false) as is_read,\n--   created_at,\n--   updated_at,\n--   data,\n--   link,\n--   related_id\n-- FROM notifications;"}	fix_notifications_schema_complete
20260325111616	{"-- Add fields for automatic calendar synchronization\nALTER TABLE configuracao_agenda\nADD COLUMN IF NOT EXISTS calendar_ics_url TEXT,\nADD COLUMN IF NOT EXISTS last_calendar_sync TIMESTAMPTZ,\nADD COLUMN IF NOT EXISTS auto_sync_enabled BOOLEAN DEFAULT false"}	add_calendar_ics_url
20260331000000	{"-- Adiciona campo para controlar se a forma de pagamento é obrigatória no orçamento\nALTER TABLE templates\nADD COLUMN IF NOT EXISTS forma_pagamento_obrigatoria BOOLEAN NOT NULL DEFAULT false","COMMENT ON COLUMN templates.forma_pagamento_obrigatoria IS \n  'Quando ativo, o cliente é obrigado a selecionar uma forma de pagamento antes de enviar o orçamento. Só tem efeito se o template tiver formas de pagamento cadastradas.'"}	add_forma_pagamento_obrigatoria
20260410	{"-- ============================================================\n-- Migration: Atualiza check_date_availability com regras avançadas\n-- Versão: 2.0\n-- Data: 2026-04-10\n-- \n-- Adiciona verificação de:\n--   1. Períodos de bloqueio (férias)\n--   2. Regras de massa: dias da semana, pares/ímpares, feriados, semanas alternadas\n-- ============================================================\n\nCREATE OR REPLACE FUNCTION \\"public\\".\\"check_date_availability\\"(\\"p_user_id\\" \\"uuid\\", \\"p_data_evento\\" \\"date\\") RETURNS \\"jsonb\\"\n    LANGUAGE \\"plpgsql\\" SECURITY DEFINER\n    SET \\"search_path\\" TO 'public'\n    AS $$\nDECLARE\n  v_config record;\n  v_eventos_count integer;\n  v_bloqueada boolean;\n  v_motivo_bloqueio text;\n  v_result jsonb;\n  v_dia_semana integer;      -- 0=Dom, 6=Sab (EXTRACT DOW)\n  v_dia_mes integer;         -- 1-31\n  v_num_semana integer;      -- semana relativa à data de início\n  v_diff_dias integer;\n  v_eh_semana_par boolean;\n  v_em_periodo boolean;\n  v_eh_feriado boolean;\nBEGIN\n\n  -- 1. Buscar configuração da agenda\n  SELECT *\n  INTO v_config\n  FROM configuracao_agenda\n  WHERE user_id = p_user_id;\n\n  -- Agenda inexistente ou inativa → disponível\n  IF v_config IS NULL OR NOT v_config.agenda_ativa THEN\n    RETURN jsonb_build_object(\n      'disponivel', true,\n      'status', 'inativa',\n      'eventos_atual', 0,\n      'eventos_max', 999,\n      'modo_aviso', 'informativo',\n      'bloqueada', false,\n      'mensagem', 'Sistema de agenda não está ativo',\n      'agenda_ativa', false\n    );\n  END IF;\n\n  -- 2. Data bloqueada manualmente (prioridade máxima)\n  SELECT EXISTS(\n    SELECT 1 FROM datas_bloqueadas\n    WHERE user_id = p_user_id AND data_bloqueada = p_data_evento\n  ) INTO v_bloqueada;\n\n  IF v_bloqueada THEN\n    RETURN jsonb_build_object(\n      'disponivel', false,\n      'status', 'bloqueada',\n      'eventos_atual', 0,\n      'eventos_max', v_config.eventos_max_por_dia,\n      'modo_aviso', v_config.modo_aviso,\n      'bloqueada', true,\n      'mensagem', 'Esta data está bloqueada pelo fotógrafo.',\n      'agenda_ativa', true\n    );\n  END IF;\n\n  -- 3. Períodos de bloqueio (férias) — independente de regras_massa_ativas\n  SELECT EXISTS(\n    SELECT 1 FROM periodos_bloqueados\n    WHERE user_id = p_user_id\n      AND p_data_evento BETWEEN data_inicio AND data_fim\n  ) INTO v_em_periodo;\n\n  IF v_em_periodo THEN\n    RETURN jsonb_build_object(\n      'disponivel', false,\n      'status', 'bloqueada',\n      'eventos_atual', 0,\n      'eventos_max', v_config.eventos_max_por_dia,\n      'modo_aviso', v_config.modo_aviso,\n      'bloqueada', true,\n      'mensagem', 'Data dentro de um período de férias ou bloqueio.',\n      'agenda_ativa', true\n    );\n  END IF;\n\n  -- 4. Regras de massa (somente se ativas)\n  IF COALESCE(v_config.regras_massa_ativas, false) THEN\n\n    -- 4a. Dias da semana bloqueados (0=Dom, 1=Seg...6=Sab)\n    v_dia_semana := EXTRACT(DOW FROM p_data_evento)::integer;\n    IF v_config.dias_semana_bloqueados IS NOT NULL\n       AND v_dia_semana = ANY(v_config.dias_semana_bloqueados) THEN\n      RETURN jsonb_build_object(\n        'disponivel', false,\n        'status', 'bloqueada',\n        'eventos_atual', 0,\n        'eventos_max', v_config.eventos_max_por_dia,\n        'modo_aviso', v_config.modo_aviso,\n        'bloqueada', true,\n        'mensagem', 'Este dia da semana está bloqueado.',\n        'agenda_ativa', true\n      );\n    END IF;\n\n    -- 4b. Dias pares/ímpares do mês\n    v_dia_mes := EXTRACT(DAY FROM p_data_evento)::integer;\n\n    IF v_config.regra_par_impar = 'pares' AND v_dia_mes % 2 = 0 THEN\n      RETURN jsonb_build_object(\n        'disponivel', false,\n        'status', 'bloqueada',\n        'eventos_atual', 0,\n        'eventos_max', v_config.eventos_max_por_dia,\n        'modo_aviso', v_config.modo_aviso,\n        'bloqueada', true,\n        'mensagem', 'Datas pares estão bloqueadas.',\n        'agenda_ativa', true\n      );\n    END IF;\n\n    IF v_config.regra_par_impar = 'impares' AND v_dia_mes % 2 != 0 THEN\n      RETURN jsonb_build_object(\n        'disponivel', false,\n        'status', 'bloqueada',\n        'eventos_atual', 0,\n        'eventos_max', v_config.eventos_max_por_dia,\n        'modo_aviso', v_config.modo_aviso,\n        'bloqueada', true,\n        'mensagem', 'Datas ímpares estão bloqueadas.',\n        'agenda_ativa', true\n      );\n    END IF;\n\n    -- 4c. Feriados (nacionais e personalizados)\n    IF COALESCE(v_config.bloquear_feriados, false) THEN\n      SELECT EXISTS(\n        SELECT 1 FROM feriados\n        WHERE user_id = p_user_id\n          AND data = p_data_evento\n      ) INTO v_eh_feriado;\n\n      IF v_eh_feriado THEN\n        RETURN jsonb_build_object(\n          'disponivel', false,\n          'status', 'bloqueada',\n          'eventos_atual', 0,\n          'eventos_max', v_config.eventos_max_por_dia,\n          'modo_aviso', v_config.modo_aviso,\n          'bloqueada', true,\n          'mensagem', 'Esta data é um feriado bloqueado.',\n          'agenda_ativa', true\n        );\n      END IF;\n    END IF;\n\n    -- 4d. Semanas alternadas (trabalha semanas pares ou ímpares)\n    IF v_config.regra_semanal IS NOT NULL\n       AND v_config.regra_semanal != 'nenhum'\n       AND v_config.regra_semanal_inicio IS NOT NULL THEN\n\n      v_diff_dias := (p_data_evento - v_config.regra_semanal_inicio)::integer;\n      v_num_semana := v_diff_dias / 7;\n      v_eh_semana_par := (v_num_semana % 2 = 0);\n\n      -- \\"trabalha_pares\\" = bloqueia semanas ímpares\n      IF v_config.regra_semanal = 'trabalha_pares' AND NOT v_eh_semana_par THEN\n        RETURN jsonb_build_object(\n          'disponivel', false,\n          'status', 'bloqueada',\n          'eventos_atual', 0,\n          'eventos_max', v_config.eventos_max_por_dia,\n          'modo_aviso', v_config.modo_aviso,\n          'bloqueada', true,\n          'mensagem', 'Semana bloqueada (disponível apenas semanas alternadas).',\n          'agenda_ativa', true\n        );\n      END IF;\n\n      -- \\"trabalha_impares\\" = bloqueia semanas pares\n      IF v_config.regra_semanal = 'trabalha_impares' AND v_eh_semana_par THEN\n        RETURN jsonb_build_object(\n          'disponivel', false,\n          'status', 'bloqueada',\n          'eventos_atual', 0,\n          'eventos_max', v_config.eventos_max_por_dia,\n          'modo_aviso', v_config.modo_aviso,\n          'bloqueada', true,\n          'mensagem', 'Semana bloqueada (disponível apenas semanas alternadas).',\n          'agenda_ativa', true\n        );\n      END IF;\n\n    END IF;\n\n  END IF; -- fim regras_massa_ativas\n\n  -- 5. Verificar ocupação por eventos\n  SELECT COUNT(*)\n  INTO v_eventos_count\n  FROM eventos_agenda\n  WHERE user_id = p_user_id\n    AND data_evento = p_data_evento\n    AND status IN ('confirmado', 'pendente');\n\n  IF v_eventos_count = 0 THEN\n    v_result := jsonb_build_object(\n      'disponivel', true,\n      'status', 'disponivel',\n      'eventos_atual', v_eventos_count,\n      'eventos_max', v_config.eventos_max_por_dia,\n      'modo_aviso', v_config.modo_aviso,\n      'bloqueada', false,\n      'mensagem', 'Data disponível!',\n      'agenda_ativa', true\n    );\n  ELSIF v_eventos_count < v_config.eventos_max_por_dia THEN\n    v_result := jsonb_build_object(\n      'disponivel', true,\n      'status', 'parcial',\n      'eventos_atual', v_eventos_count,\n      'eventos_max', v_config.eventos_max_por_dia,\n      'modo_aviso', v_config.modo_aviso,\n      'bloqueada', false,\n      'mensagem', format('Disponibilidade limitada: %s de %s vagas preenchidas',\n        v_eventos_count, v_config.eventos_max_por_dia),\n      'agenda_ativa', true\n    );\n  ELSE\n    v_result := jsonb_build_object(\n      'disponivel', false,\n      'status', 'ocupada',\n      'eventos_atual', v_eventos_count,\n      'eventos_max', v_config.eventos_max_por_dia,\n      'modo_aviso', v_config.modo_aviso,\n      'bloqueada', false,\n      'mensagem', 'Já temos um evento para esta data.',\n      'agenda_ativa', true\n    );\n  END IF;\n\n  RETURN v_result;\nEND;\n$$","-- Garantir permissões\nGRANT EXECUTE ON FUNCTION public.check_date_availability(uuid, date) TO anon","GRANT EXECUTE ON FUNCTION public.check_date_availability(uuid, date) TO authenticated","GRANT EXECUTE ON FUNCTION public.check_date_availability(uuid, date) TO service_role"}	update_check_date_availability_v2
20260415	{"-- Migration: Melhorias Priceus: Agenda em Templates e Carrossel de Produtos\n-- Data: 2026-04-15\n\n-- 1. Adicionar coluna para ignorar a obrigatoriedade da data (Agenda Global) no Template\nALTER TABLE templates \nADD COLUMN IF NOT EXISTS ignorar_agenda_global BOOLEAN DEFAULT false","-- 2. Adicionar suporte a múltiplas imagens e carrossel automático no Produto\nALTER TABLE produtos \nADD COLUMN IF NOT EXISTS imagens TEXT[] DEFAULT ARRAY[]::TEXT[],\nADD COLUMN IF NOT EXISTS carrossel_automatico BOOLEAN DEFAULT false"}	melhorias_priceus
