20260528100000	{"-- ==========================================================\n-- Migration: Adicionar lead_id na tabela eventos_agenda\n--   e criar a chave estrangeira para a tabela leads.\n-- Data: 2026-05-28\n-- ==========================================================\n\n-- 1. Adicionar coluna lead_id na tabela eventos_agenda se não existir\nALTER TABLE public.eventos_agenda \n  ADD COLUMN IF NOT EXISTS lead_id UUID REFERENCES public.leads(id) ON DELETE SET NULL","-- 2. Criar índice para performance em buscas por lead_id se não existir\nCREATE INDEX IF NOT EXISTS idx_eventos_agenda_lead_id ON public.eventos_agenda(lead_id)","-- 3. Documentação\nCOMMENT ON COLUMN public.eventos_agenda.lead_id IS 'ID do lead associado a este evento de agenda (CRM)'"}	add_lead_id_to_eventos_agenda
20260529090000	{"-- ============================================================\n-- Migração: Forma de Pagamento Padrão (Pré-selecionada)\n-- Data: 2026-05-29\n-- Objetivo: Permite ao fotógrafo marcar uma forma de pagamento\n--           como \\"padrão\\", que será pré-selecionada para o cliente\n--           ao abrir o orçamento.\n-- ============================================================\n\nALTER TABLE formas_pagamento\n  ADD COLUMN IF NOT EXISTS is_default boolean NOT NULL DEFAULT false","-- Garante que apenas 1 forma por template pode ser marcada como padrão.\n-- A constraint é do tipo CHECK parcial via trigger (Postgres não suporta\n-- unique parcial em booleanos de forma nativa, então usamos um índice).\nCREATE UNIQUE INDEX IF NOT EXISTS formas_pagamento_one_default_per_template\n  ON formas_pagamento (template_id)\n  WHERE is_default = true","COMMENT ON COLUMN formas_pagamento.is_default IS\n  'Quando true, esta forma de pagamento é pré-selecionada automaticamente para o cliente ao abrir o orçamento.'"}	add_forma_pagamento_default
